from flask import Flask, request, jsonify, Response
import jwt
import requests
import os

app = Flask(__name__)

SECRET_KEY = os.getenv('JWT_SECRET_KEY', 'dev-secret-key')
BACKEND_SERVICE_URL = os.getenv('BACKEND_SERVICE_URL', 'http://localhost:5001')

def extract_token():
    auth_header = request.headers.get('Authorization')
    if not auth_header:
        return None
    
    parts = auth_header.split()
    if len(parts) != 2 or parts[0].lower() != 'bearer':
        return None
    
    return parts[1]

def decode_token(token):
    try:
        decoded = jwt.decode(token, options={"verify_signature": False})
        return decoded
    except jwt.DecodeError:
        return None
    except Exception:
        return None

def forward_to_backend(path, claims):
    backend_url = f"{BACKEND_SERVICE_URL}{path}"
    
    headers = dict(request.headers)
    headers['X-User-Id'] = str(claims.get('user_id', ''))
    headers['X-User-Email'] = str(claims.get('email', ''))
    headers['X-User-Role'] = str(claims.get('role', ''))
    headers['X-User-Claims'] = str(claims)
    
    if 'Host' in headers:
        del headers['Host']
    
    try:
        if request.method == 'GET':
            response = requests.get(backend_url, headers=headers, params=request.args, timeout=30)
        elif request.method == 'POST':
            response = requests.post(backend_url, headers=headers, json=request.get_json(), params=request.args, timeout=30)
        elif request.method == 'PUT':
            response = requests.put(backend_url, headers=headers, json=request.get_json(), params=request.args, timeout=30)
        elif request.method == 'DELETE':
            response = requests.delete(backend_url, headers=headers, params=request.args, timeout=30)
        elif request.method == 'PATCH':
            response = requests.patch(backend_url, headers=headers, json=request.get_json(), params=request.args, timeout=30)
        else:
            return jsonify({'error': 'Method not supported'}), 405
        
        return Response(response.content, status=response.status_code, headers=dict(response.headers))
    except requests.exceptions.RequestException as e:
        return jsonify({'error': 'Backend service unavailable', 'details': str(e)}), 503

@app.route('/', defaults={'path': ''}, methods=['GET', 'POST', 'PUT', 'DELETE', 'PATCH'])
@app.route('/<path:path>', methods=['GET', 'POST', 'PUT', 'DELETE', 'PATCH'])
def gateway(path):
    token = extract_token()
    
    if not token:
        return jsonify({'error': 'Missing or invalid Authorization header'}), 401
    
    claims = decode_token(token)
    
    if claims is None:
        return jsonify({'error': 'Invalid token format'}), 401
    
    return forward_to_backend(f'/{path}', claims)

@app.route('/health', methods=['GET'])
def health():
    return jsonify({'status': 'healthy', 'service': 'api-gateway'}), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=True)